void MOD_mkReservationStationAlu::dump_VCD(tVCDDumpType dt,
					   unsigned int levels,
					   MOD_mkReservationStationAlu &backing)
{
  vcd_defs(dt, backing);
  vcd_prims(dt, backing);
}

